import os
import time
from prometheus_client import Gauge, start_http_server

DB_CREDENTIALS_INFO = Gauge(
    "db_credentials_info",
    "Database credentials information exposed as labels",
    ["username", "password", "host", "connection_string"],
)

def load_db_credentials():
    username = os.getenv("DB_USERNAME", "")
