def main():
    port = int(os.getenv("METRICS_PORT", "8000"))
    start_http_server(port)
    while True:
        update_metrics()
        time.sleep(int(os.getenv("UPDATE_INTERVAL_SECONDS", "60")))

if __name__ == "__main__":
    main()